  "content": "import { useState, useEffect } from 'react';
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Card } from "@/components/ui/card";

export default function WeddingInvitation() {
  // 婚礼日期 - 这里设置为2026年6月1日作为示例
  const weddingDate = new Date('2026-06-01T12:00:00');

  // 倒计时状态
  const [timeLeft, setTimeLeft] = useState({
    days: 0,
    hours: 0,
    minutes: 0,
    seconds: 0
  });

  // 轮播图状态
  const [currentPhotoIndex, setCurrentPhotoIndex] = useState(0);

  // 留言状态
  const [guestName, setGuestName] = useState('');
  const [message, setMessage] = useState('');
  const [messages, setMessages] = useState([
    { id: 1, name: '张三', message: '祝你们百年好合，永结同心！', date: '2026-02-01' },
    { id: 2, name: '李四', message: '新婚快乐，早生贵子！', date: '2026-02-03' }
  ]);

  // 婚纱照数组（使用占位图片）
  const weddingPhotos = [
    'https://images.unsplash.com/photo-1511795409834-ef04bbd61622?w=800&h=600&fit=crop',
    'https://images.unsplash.com/photo-1523287076374-d3b0e8a7c7f8?w=800&h=600&fit=crop',
    'https://images.unsplash.com/photo-1543007615-13a2de3c1d5a?w=800&h=600&fit=crop'
  ];

  // 计算倒计时
  useEffect(() => {
    const calculateTimeLeft = () => {
      const now = new Date().getTime();
      const distance = weddingDate.getTime() - now;

      if (distance > 0) {
        const days = Math.floor(distance / (1000 * 60 * 60 * 24));
        const hours = Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
        const minutes = Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60));
        const seconds = Math.floor((distance % (1000 * 60)) / 1000);

        setTimeLeft({ days, hours, minutes, seconds });
      }
    };

    calculateTimeLeft();
    const timer = setInterval(calculateTimeLeft, 1000);

    return () => clearInterval(timer);
  }, []);

  // 轮播图自动切换
  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentPhotoIndex((prevIndex) => 
        (prevIndex + 1) % weddingPhotos.length
      );
    }, 5000);

    return () => clearInterval(interval);
  }, [weddingPhotos.length]);

  // 处理留言提交
  const handleMessageSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (guestName.trim() && message.trim()) {
      const newMessage = {
        id: Date.now(),
        name: guestName,
        message: message,
        date: new Date().toISOString().split('T')[0]
      };
      setMessages([newMessage, ...messages]);
      setGuestName('');
      setMessage('');
    }
  };

  // 切换轮播图
  const goToPhoto = (index: number) => {
    setCurrentPhotoIndex(index);
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-pink-50 to-red-50">
      {/* Hero Section */}
      <div className="relative bg-gradient-to-r from-pink-400 to-red-400 text-white py-16 px-4">
        <div className="max-w-4xl mx-auto text-center">
          <h1 className="text-4xl md:text-6xl font-bold mb-4">我们结婚啦！</h1>
          <p className="text-xl md:text-2xl mb-8">诚挚邀请您见证我们的幸福时刻</p>

          {/* Countdown Timer */}
          <div className="bg-white/20 backdrop-blur-sm rounded-lg p-6 mb-8">
            <h2 className="text-2xl font-semibold mb-4">距离婚礼还有</h2>
            <div className="flex justify-center space-x-4">
              <div className="text-center">
                <div className="text-3xl md:text-4xl font-bold">{timeLeft.days}</div>
                <div className="text-sm">天</div>
              </div>
              <div className="text-center">
                <div className="text-3xl md:text-4xl font-bold">{timeLeft.hours}</div>
                <div className="text-sm">小时</div>
              </div>
              <div className="text-center">
                <div className="text-3xl md:text-4xl font-bold">{timeLeft.minutes}</div>
                <div className="text-sm">分钟</div>
              </div>
              <div className="text-center">
                <div className="text-3xl md:text-4xl font-bold">{timeLeft.seconds}</div>
                <div className="text-sm">秒</div>
              </div>
            </div>
          </div>

          <div className="text-lg">
            <p>婚礼时间：2026年6月1日 中午12:00</p>
          </div>
        </div>
      </div>

      <div className="max-w-6xl mx-auto px-4 py-12">
        {/* Couple Introduction */}
        <section className="mb-16 text-center">
          <h2 className="text-3xl font-bold text-gray-800 mb-8">新人介绍</h2>
          <div className="grid md:grid-cols-2 gap-8">
            <div className="bg-white rounded-lg shadow-md p-6">
              <div className="w-32 h-32 mx-auto mb-4 rounded-full bg-gradient-to-br from-pink-300 to-red-300 flex items-center justify-center text-white text-4xl font-bold">
                新郎
              </div>
              <h3 className="text-xl font-semibold mb-2">张先生</h3>
              <p className="text-gray-600">温柔体贴，才华横溢</p>
            </div>
            <div className="bg-white rounded-lg shadow-md p-6">
              <div className="w-32 h-32 mx-auto mb-4 rounded-full bg-gradient-to-br from-pink-300 to-red-300 flex items-center justify-center text-white text-4xl font-bold">
                新娘
              </div>
              <h3 className="text-xl font-semibold mb-2">李女士</h3>
              <p className="text-gray-600">美丽善良，聪慧大方</p>
            </div>
          </div>
        </section>

        {/* Photo Gallery */}
        <section className="mb-16">
          <h2 className="text-3xl font-bold text-gray-800 mb-8 text-center">我们的婚纱照</h2>
          <div className="relative bg-white rounded-lg shadow-md overflow-hidden">
            <img 
              src={weddingPhotos[currentPhotoIndex]} 
              alt={`Wedding photo ${currentPhotoIndex + 1}`}
              className="w-full h-96 object-cover"
            />
            <div className="absolute bottom-4 left-1/2 transform -translate-x-1/2 flex space-x-2">
              {weddingPhotos.map((_, index) => (
                <button
                  key={index}
                  onClick={() => goToPhoto(index)}
                  className={`w-3 h-3 rounded-full ${
                    index === currentPhotoIndex ? 'bg-white' : 'bg-white/50'
                  }`}
                />
              ))}
            </div>
          </div>
        </section>

        {/* Wedding Location */}
        <section className="mb-16">
          <h2 className="text-3xl font-bold text-gray-800 mb-8 text-center">婚礼地点</h2>
          <div className="bg-white rounded-lg shadow-md p-6">
            <div className="text-center mb-4">
              <h3 className="text-xl font-semibold">北京王府井大酒店</h3>
              <p className="text-gray-600">北京市东城区王府井大街1号</p>
            </div>
            <div className="aspect-video bg-gray-200 rounded-lg flex items-center justify-center">
              <div className="text-center">
                <div className="text-4xl mb-2">📍</div>
                <p className="text-gray-600">地图加载中...</p>
                <p className="text-sm text-gray-500 mt-2">实际应用中会显示交互式地图</p>
              </div>
            </div>
          </div>
        </section>

        {/* Guest Messages */}
        <section>
          <h2 className="text-3xl font-bold text-gray-800 mb-8 text-center">祝福留言</h2>

          {/* Message Form */}
          <Card className="mb-8 p-6">
            <h3 className="text-xl font-semibold mb-4">留下您的祝福</h3>
            <form onSubmit={handleMessageSubmit}>
              <div className="mb-4">
                <Input
                  placeholder="您的姓名"
                  value={guestName}
                  onChange={(e) => setGuestName(e.target.value)}
                  className="mb-4"
                />
                <Textarea
                  placeholder="写下您的祝福..."
                  value={message}
                  onChange={(e) => setMessage(e.target.value)}
                  rows={4}
                />
              </div>
              <Button type="submit" className="bg-pink-500 hover:bg-pink-600">
                发送祝福
              </Button>
            </form>
          </Card>

          {/* Messages List */}
          <div className="space-y-4">
            {messages.map((msg) => (
              <Card key={msg.id} className="p-4">
                <div className="flex justify-between items-start mb-2">
                  <h4 className="font-semibold text-lg">{msg.name}</h4>
                  <span className="text-sm text-gray-500">{msg.date}</span>
                </div>
                <p className="text-gray-700">{msg.message}</p>
              </Card>
            ))}
          </div>
        </section>
      </div>

      {/* Footer */}
      <footer className="bg-gray-800 text-white py-6 text-center">
        <p>感谢您的祝福与见证 ❤️</p>
      </footer>
    </div>
  );
}"
}
